// Limpa CNPJ - remove tudo que não é número
const items = $input.all();
return items.map(item => {
  const cnpjLimpo = (item.json.cnpj || '').replace(/\D/g, '');
  return { json: { cnpj_limpo: cnpjLimpo } };
});

const items = $input.all();
return items.map(item => {
  const d = item.json;

  // Se houve erro
  if (d.error || d.statusCode >= 400 || d.message) {
    return { json: { sucesso: false, mensagem: 'CNPJ não encontrado na Receita Federal' } };
  }

  // Extrai atividade principal
  let segmento = '';
  if (d.cnae_fiscal_descricao) {
    segmento = d.cnae_fiscal_descricao;
  } else if (d.cnaes_secundarios && d.cnaes_secundarios.length > 0) {
    segmento = d.cnaes_secundarios[0].descricao || '';
  }

  return {
    json: {
      sucesso: true,
      cnpj: d.cnpj || '',
      razao_social: d.razao_social || '',
      nome_fantasia: d.nome_fantasia || d.razao_social || '',
      segment: segmento,
      city: d.municipio || '',
      state: d.uf || '',
      phone: d.ddd_telefone_1 || '',
      email: d.email || '',
      endereco: `${d.logradouro || ''}, ${d.numero || ''} - ${d.bairro || ''}`,
      cep: d.cep || '',
      situacao: d.descricao_situacao_cadastral || 'ATIVA',
      abertura: d.data_inicio_atividade || ''
    }
  };
});
